// --- タイトルの取得 ---
const rawTitle = document.title || '';
const title = rawTitle.replace(/\s*[-–]\s*Gemini\s*$/i, '').trim() || '無題の会話';

// --- 会話内容の取得 ---
const userEls = document.querySelectorAll(
  '.query-text, .user-query-text, [data-message-author-role="user"] .whitespace-pre-wrap'
);
const modelEls = document.querySelectorAll(
  'model-response .markdown, .model-response-text, [data-message-author-role="model"] .markdown'
);

const userTexts  = Array.from(userEls).map(el => el.innerText.trim()).filter(Boolean);
const modelTexts = Array.from(modelEls).map(el => el.innerText.trim()).filter(Boolean);

const lines = [];
const len = Math.max(userTexts.length, modelTexts.length);
for (let i = 0; i < len; i++) {
  if (userTexts[i])  lines.push('**ユーザー:**\n\n' + userTexts[i]);
  if (modelTexts[i]) lines.push('**Gemini:**\n\n' + modelTexts[i]);
}

const content = lines.length > 0
  ? lines.join('\n\n---\n\n')
  : document.body.innerText.slice(0, 8000);

automaSetVariable('title',   title);
automaSetVariable('content', content);
automaNextBlock({ data: '' });

// --- 設定を globalData から読み込む ---
const cfg   = JSON.parse(automaRefData('globalData') || '{}');
const token = cfg.github_token;
const owner = cfg.github_owner || 'kotaoue';
const repo  = cfg.github_repo  || 'Journal';
const base  = cfg.base_branch  || 'main';

if (!token) throw new Error('globalData に github_token が設定されていません。');

const title   = automaRefData('variables', 'title');
const content = automaRefData('variables', 'content');

const api = (path, opts) => fetch(`https://api.github.com/repos/${owner}/${repo}/${path}`, {
  ...opts,
  headers: {
    'Authorization':        `Bearer ${token}`,
    'Accept':               'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
    'Content-Type':         'application/json',
    ...opts?.headers
  }
}).then(async r => { const j = await r.json(); if (!r.ok) throw new Error(JSON.stringify(j)); return j; });

// --- スラッグ生成 ---
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\u3041-\u3096\u30a1-\u30f6\u4e00-\u9faf]/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '') || 'untitled';

// --- 日付・パス ---
const today = new Date().toISOString().slice(0, 10);
const year  = today.slice(0, 4);
const branch = `gemini/${today}-${slug}`;
const path   = `tech/${year}/gemini-thread-import/${slug}.md`;

const fileBody = `# ${title}\n\n> インポート日: ${today}  \n> ソース: https://gemini.google.com/app?hl=ja\n\n---\n\n${content}\n`;
const encoded  = btoa(unescape(encodeURIComponent(fileBody)));

// 1. デフォルトブランチの最新 SHA を取得
const branchInfo = await api(`branches/${base}`);
const sha = branchInfo.commit.sha;

// 2. 新しいブランチを作成
await api('git/refs', {
  method: 'POST',
  body: JSON.stringify({ ref: `refs/heads/${branch}`, sha })
});

// 3. ファイルを作成
await api(`contents/${path}`, {
  method: 'PUT',
  body: JSON.stringify({
    message: `feat(gemini): ${title}`,
    content: encoded,
    branch
  })
});

// 4. PR を作成
const pr = await api('pulls', {
  method: 'POST',
  body: JSON.stringify({
    title: `feat(gemini): ${title}`,
    body:  `Gemini との会話「${title}」を \`${path}\` としてインポートしました。`,
    head:  branch,
    base
  })
});

automaNextBlock({ data: `PR opened: ${pr.html_url}` });
